import React, { useState, useEffect } from 'react';

export default function App() {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => {
      setTime(new Date());
      if (window.lucide) window.lucide.createIcons();
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const formatTime = (date) => ({
    hours: String(date.getHours()).padStart(2, '0'),
    minutes: String(date.getMinutes()).padStart(2, '0'),
    seconds: String(date.getSeconds()).padStart(2, '0'),
    day: date.toLocaleDateString('en-US', { weekday: 'long' }),
    date: date.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })
  });

  const { hours, minutes, seconds, day, date } = formatTime(time);

  return (
    <div className="min-h-screen bg-neutral-950 flex flex-col items-center justify-center p-6 text-neutral-100 font-sans selection:bg-blue-500/30">
      <div className="relative w-full max-w-sm">
        {/* Ambient Glow */}
        <div className="absolute -inset-1 bg-gradient-to-tr from-blue-600/20 to-purple-600/20 blur-3xl rounded-full"></div>

        <div className="relative bg-neutral-900/40 backdrop-blur-2xl border border-neutral-800 p-8 rounded-[2.5rem] shadow-2xl shadow-black/60 overflow-hidden">
          <div className="flex justify-between items-center mb-10">
            <div className="w-10 h-10 flex items-center justify-center bg-neutral-950/50 rounded-2xl border border-neutral-800 shadow-inner">
              <i data-lucide="clock" className="text-blue-500 w-5 h-5"></i>
            </div>
            <div className="flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              <span className="text-[10px] font-bold tracking-widest uppercase text-neutral-500">Live Sync</span>
            </div>
          </div>

          <div className="text-center mb-10">
            <div className="inline-flex items-baseline justify-center">
              <h1 className="text-8xl font-thin tracking-tighter tabular-nums text-white">
                {hours}<span className="text-blue-500/50">:</span>{minutes}
              </h1>
              <span className="text-3xl font-light text-neutral-600 ml-2 tabular-nums">:{seconds}</span>
            </div>
            <div className="mt-4 flex flex-col gap-1">
              <p className="text-neutral-200 font-medium tracking-tight text-lg">{day}</p>
              <p className="text-neutral-500 text-sm tracking-wide">{date}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="bg-neutral-950/40 p-4 rounded-3xl border border-neutral-800/50 flex flex-col items-center">
              <span className="text-[10px] text-neutral-500 uppercase tracking-widest mb-1">Timezone</span>
              <span className="text-sm font-semibold">{Intl.DateTimeFormat().resolvedOptions().timeZone.split('/')[1] || 'Local'}</span>
            </div>
            <div className="bg-neutral-950/40 p-4 rounded-3xl border border-neutral-800/50 flex flex-col items-center">
              <span className="text-[10px] text-neutral-500 uppercase tracking-widest mb-1">Precision</span>
              <span className="text-sm font-semibold">Atomic</span>
            </div>
          </div>
        </div>
      </div>

      <footer className="text-center p-8 text-neutral-500 text-xs opacity-60 flex justify-center items-center gap-1.5 mt-auto">
        <span>Powered by</span> 
        <img src="https://forge-app.vercel.app/logo.png" alt="Forge" className="w-3.5 h-3.5 rounded-sm object-cover" /> 
        <a href="https://forge-app.vercel.app" className="text-blue-500 font-semibold no-underline hover:text-blue-400">FORGE</a>
      </footer>
    </div>
  );
}
